<template><div><h2>🤝 拼团管理</h2><el-button type="primary" size="small" @click="show=true;reset()">+ 新建拼团</el-button><el-table :data="list" stripe size="small" style="margin-top:8px"><el-table-column prop="product_name" label="产品"/><el-table-column label="折扣"><template #default="{row}">{{ Math.round(row.discount_rate*100) }}%</template></el-table-column><el-table-column label="进度"><template #default="{row}">{{ row.current_members }}/{{ row.min_members }}人</template></el-table-column><el-table-column prop="start_time" label="开始"/><el-table-column prop="end_time" label="结束"/><el-table-column label="状态"><template #default="{row}"><el-tag :type="row.current_members>=row.min_members?'success':'warning'" size="small">{{ row.current_members>=row.min_members?'已成团':'拼团中' }}</el-tag></template></el-table-column></el-table><el-dialog v-model="show" title="新建拼团" width="400px"><el-form label-width="80px"><el-form-item label="产品"><el-input v-model="f.title"/></el-form-item><el-form-item label="成团人数"><el-input-number v-model="f.minMembers" :min="2" :max="10"/></el-form-item><el-form-item label="折扣率"><el-input-number v-model="f.discountRate" :min="0.1" :max="0.99" :step="0.05"/></el-form-item><el-form-item label="开始"><el-input v-model="f.startTime" type="datetime-local"/></el-form-item><el-form-item label="结束"><el-input v-model="f.endTime" type="datetime-local"/></el-form-item></el-form><template #footer><el-button @click="show=false">取消</el-button><el-button type="primary" @click="save">保存</el-button></template></el-dialog></div></template>
<script setup>import {ref,reactive,onMounted} from 'vue';import request from '@/utils/request';import {ElMessage} from 'element-plus';const list=ref([]);const show=ref(false);const f=reactive({title:'',productId:1,minMembers:3,discountRate:0.7,startTime:'',endTime:''});function reset(){Object.assign(f,{title:'',productId:1,minMembers:3,discountRate:0.7,startTime:'',endTime:''})}async function fetch(){try{list.value=await request.get('/group-buys')||[]}catch{}}async function save(){try{await request.post('/group-buys',f);show.value=false;fetch();ElMessage.success('已创建')}catch{}}onMounted(fetch)</script>
